const fs = require('fs');
const csv = fs.readFileSync('[EXCLUDED_GENERATED_ARTIFACT]','utf8').trim().split(/\n/);
const rows = csv.slice(1).map(line => line.split(/,(?=(?:[^"]*"[^"]*")*[^"]*$)/));
const ids = rows.map(r => r[0]);
const priorities = rows.map(r => Number(r[5]));
const sorted = [...priorities].sort((a,b)=>b-a);
const okOrder = JSON.stringify(priorities) === JSON.stringify(sorted);
const hardCount = rows.filter(r => r[9] === 'yes').length;
console.log(JSON.stringify({rows: rows.length, ids, priorities, okOrder, hardCount}, null, 2));
